# Explorer notes for S46-T1-A-E2: follow packet fixture + instruction contract
def assess(record: dict) -> str:
    required = {'watermark', 'window_end', 'allowed_lateness', 'event_time', 'case_id'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if record["event_time"] <= record["window_end"] or record["event_time"] < record["watermark"] - record["allowed_lateness"] else "SIDE_OUTPUT_LATE_EVENT"

valid = {'case_id': 'CASO-HYO-046-1A', 'event_time': 110, 'window_end': 120, 'watermark': 115, 'allowed_lateness': 10}
invalid = {'case_id': 'CASO-HYO-046-1A', 'event_time': 210, 'window_end': 120, 'watermark': 115, 'allowed_lateness': 10}
incomplete = {**valid}
incomplete.pop('allowed_lateness', None)
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

